+        GenJournalLine: Record "Gen. Journal Line";
+        GLAccount: Record "G/L Account";
+        InvoiceAmount: Decimal;
+    begin
+        // [SCENARIO 606537] When Posting a Bank Deposit with several lines the Apply to Oldest is not applied properly.
+        Initialize();
